  { name: "Anna", role: "admin", lastLogin: "2026-03-20" },
  { name: "Bob", role: "user", lastLogin: "2026-03-22" },
  { name: "Cara", role: "admin", lastLogin: "2026-03-18" },
  { name: "Dave", role: "user", lastLogin: "2026-03-20" },
];

const roleOrder = { admin: 0, user: 1 };

const sorted = users.toSorted((a, b) => {
  const roleDiff = roleOrder[a.role] - roleOrder[b.role];
  if (roleDiff !== 0) return roleDiff;

  const dateDiff = new Date(b.lastLogin) - new Date(a.lastLogin);
  if (dateDiff !== 0) return dateDiff;

  return a.name.localeCompare(b.name);
});

const compareBy = (selector) => (a, b) => {
  const aValue = selector(a);
  const bValue = selector(b);
  return aValue < bValue ? -1 : aValue > bValue ? 1 : 0;
};

const compareByMany = (...rules) => (a, b) => {
  for (const { selector, order = "asc" } of rules) {
    const aValue = selector(a);
    const bValue = selector(b);

    let result = 0;

    if (typeof aValue === "string" && typeof bValue === "string") {
      result = aValue.localeCompare(bValue);
    } else {
      result = aValue - bValue;
    }

    if (result !== 0) {
      return order === "asc" ? result : -result;
    }
  }

  return 0;
};

